from dataclasses import dataclass
from typing import Dict

@dataclass
class HardwareSpec:
    provider: str
    current_qubits: int
    current_error: float
    growth_rate: float
    error_improvement: float

class HardwareProjector:
    def __init__(self, spec: HardwareSpec):
        self.spec = spec

    def project_qubits(self, years: int) -> int:
        return int(self.spec.current_qubits * (self.spec.growth_rate ** years))

    def project_error(self, years: int) -> float:
        return self.spec.current_error * (self.spec.error_improvement ** years)

    def capability_timeline(self, target_qubits: int, target_error: float) -> int:
        for year in range(1, 50):
            qubits = self.project_qubits(year)
            error = self.project_error(year)
            if qubits >= target_qubits and error <= target_error:
                return year
        return -1  # Target not reachable in 50 years

