from dataclasses import dataclass
from typing import List, Dict
from enum import Enum

class ThreatLevel(Enum):
    LOW = 1
    MEDIUM = 2
    HIGH = 3
    CRITICAL = 4

@dataclass
class CryptoAsset:
    name: str
    algorithm: str
    threat_level: ThreatLevel
    pqc_replacement: str

class MigrationPlanner:
    def __init__(self):
        self.assets: List[CryptoAsset] = []

    def add_asset(self, asset: CryptoAsset):
        self.assets.append(asset)

    def prioritize(self) -> List[Dict]:
        sorted_assets = sorted(self.assets, key=lambda x: x.threat_level.value, reverse=True)
        return [{
            'name': a.name,
            'algorithm': a.algorithm,
            'threat': a.threat_level.name,
            'replacement': a.pqc_replacement
        } for a in sorted_assets]

    def migration_phases(self) -> Dict[str, List[str]]:
        phases = {
            'Phase 1 - Immediate': [],
            'Phase 2 - Short-term': [],
            'Phase 3 - Medium-term': []
        }
        for a in self.assets:
            if a.threat_level.value >= 3:
                phases['Phase 1 - Immediate'].append(a.name)
            elif a.threat_level.value >= 2:
                phases['Phase 2 - Short-term'].append(a.name)
            else:
                phases['Phase 3 - Medium-term'].append(a.name)
        return phases

