from dataclasses import dataclass
from typing import List, Dict
from enum import Enum

class Priority(Enum):
    IMMEDIATE = 1
    SHORT_TERM = 2
    MEDIUM_TERM = 3
    LONG_TERM = 4

@dataclass
class Initiative:
    name: str
    priority: Priority
    investment: float
    dependencies: List[str]

class RoadmapBuilder:
    def __init__(self):
        self.initiatives: List[Initiative] = []

    def add_initiative(self, init: Initiative):
        self.initiatives.append(init)

    def by_priority(self) -> Dict[str, List[str]]:
        result = {}
        for p in Priority:
            inits = [i.name for i in self.initiatives if i.priority == p]
            if inits:
                result[p.name] = inits
        return result

    def total_investment(self) -> Dict[str, float]:
        result = {}
        for p in Priority:
            total = sum(i.investment for i in self.initiatives if i.priority == p)
            if total > 0:
                result[p.name] = total
        return result

    def execution_order(self) -> List[str]:
        ordered = []
        remaining = list(self.initiatives)

        while remaining:
            for init in remaining:
                if all(d in ordered for d in init.dependencies):
                    ordered.append(init.name)
                    remaining.remove(init)
                    break
            else:
                # No progress - add remaining in priority order
                remaining.sort(key=lambda x: x.priority.value)
                ordered.extend([i.name for i in remaining])
                break

        return ordered

