from dataclasses import dataclass
from typing import List, Dict

@dataclass
class Trend:
    name: str
    category: str
    impact: int
    confidence: float
    timeframe_years: int

class TrendAnalyzer:
    def __init__(self):
        self.trends: List[Trend] = []

    def add_trend(self, trend: Trend):
        self.trends.append(trend)

    def weighted_score(self, trend: Trend) -> float:
        return (trend.impact * trend.confidence) / max(trend.timeframe_years, 1)

    def top_trends(self, n: int = 5) -> List[Dict]:
        scored = [(t, self.weighted_score(t)) for t in self.trends]
        sorted_trends = sorted(scored, key=lambda x: x[1], reverse=True)[:n]
        return [{
            'name': t.name,
            'category': t.category,
            'score': round(s, 2)
        } for t, s in sorted_trends]

    def action_items(self) -> List[str]:
        actions = []
        for t in self.trends:
            if t.impact >= 4 and t.confidence >= 0.6 and t.timeframe_years <= 3:
                actions.append(f"Prepare for {t.name} ({t.category})")
        return actions

