from dataclasses import dataclass
from typing import Dict, List

@dataclass
class ApplicationRequirement:
    name: str
    min_qubits: int
    max_error: float
    circuit_depth: int

@dataclass
class HardwareCapability:
    qubits: int
    error_rate: float
    max_depth: int

class AdvantageEstimator:
    def __init__(self, current_capability: HardwareCapability):
        self.current = current_capability
        self.qubit_growth = 1.4
        self.error_improvement = 0.7

    def project_capability(self, years: int) -> HardwareCapability:
        qubits = int(self.current.qubits * (self.qubit_growth ** years))
        error = self.current.error_rate * (self.error_improvement ** years)
        # Depth scales with error improvement
        depth = int(self.current.max_depth / (self.error_improvement ** years))
        return HardwareCapability(qubits, error, depth)

    def years_to_advantage(self, requirement: ApplicationRequirement) -> int:
        for year in range(1, 30):
            cap = self.project_capability(year)
            if (cap.qubits >= requirement.min_qubits and
                cap.error_rate <= requirement.max_error and
                cap.max_depth >= requirement.circuit_depth):
                return year
        return -1

    def advantage_timeline(self, applications: List[ApplicationRequirement]) -> Dict[str, int]:
        return {app.name: self.years_to_advantage(app) for app in applications}
